#include <stdio.h>

typedef struct {int emp_id;char emp_name[101];long long salary;} Employee;

void display(const Employee *e){printf("Company: CodeCorp, ID: %d, Name: %s, Salary: %lld\n",e->emp_id,e->emp_name,e->salary);} 

void give_raise(Employee *e,int perc){long long inc=e->salary*perc/100;e->salary+=inc;}

int main(){int T; if(scanf("%d",&T)!=1) return 0;while(T--){Employee e1,e2;int p1,p2;scanf("%d %100s %lld",&e1.emp_id,e1.emp_name,&e1.salary);scanf("%d %100s %lld",&e2.emp_id,e2.emp_name,&e2.salary);scanf("%d %d",&p1,&p2);display(&e1);display(&e2);printf("After raise:\n");give_raise(&e1,p1);give_raise(&e2,p2);display(&e1);display(&e2);}return 0;}

